export type JournalEntryLineFieldErrors = {
  debitAccountCode?: string;
  creditAccountCode?: string;
  amount?: string;
};

export type JournalEntryFieldErrors = {
  entryDate?: string;
  processingLevel?: string;
  lines?: Record<number, JournalEntryLineFieldErrors>;
};

export function validateJournalEntryFields(input: {
  entryDate: string;
  processingLevel: string;
  lines: Array<{ debitAccountCode: string; creditAccountCode: string; amount: number }>;
}): { fieldErrors: JournalEntryFieldErrors; bannerMessages: string[] } {
  const fieldErrors: JournalEntryFieldErrors = {};
  const bannerMessages: string[] = [];

  if (!input.entryDate?.trim()) {
    fieldErrors.entryDate = 'Ngày bút toán là bắt buộc';
    bannerMessages.push(fieldErrors.entryDate);
  }

  if (!input.processingLevel?.trim()) {
    fieldErrors.processingLevel = 'Mức xử lý là bắt buộc';
    bannerMessages.push(fieldErrors.processingLevel);
  }

  if (input.lines.length === 0) {
    bannerMessages.push('Phải có ít nhất 1 dòng');
    return { fieldErrors, bannerMessages };
  }

  const lineErrors: Record<number, JournalEntryLineFieldErrors> = {};
  input.lines.forEach((line, i) => {
    const le: JournalEntryLineFieldErrors = {};
    if (!line.debitAccountCode?.trim()) {
      le.debitAccountCode = `Dòng ${i + 1}: chưa chọn TK Nợ`;
      bannerMessages.push(le.debitAccountCode);
    }
    if (!line.creditAccountCode?.trim()) {
      le.creditAccountCode = `Dòng ${i + 1}: chưa chọn TK Có`;
      bannerMessages.push(le.creditAccountCode);
    }
    if (!(Number(line.amount) > 0)) {
      le.amount = `Dòng ${i + 1}: số tiền phải > 0`;
      bannerMessages.push(le.amount);
    }
    if (Object.keys(le).length > 0) lineErrors[i] = le;
  });

  if (Object.keys(lineErrors).length > 0) {
    fieldErrors.lines = lineErrors;
  }

  return { fieldErrors, bannerMessages };
}

export function collectJournalEntryBannerMessages(fieldErrors: JournalEntryFieldErrors): string[] {
  const msgs: string[] = [];
  if (fieldErrors.entryDate) msgs.push(fieldErrors.entryDate);
  if (fieldErrors.processingLevel) msgs.push(fieldErrors.processingLevel);
  if (fieldErrors.lines) {
    Object.keys(fieldErrors.lines)
      .map(Number)
      .sort((a, b) => a - b)
      .forEach(idx => {
        const le = fieldErrors.lines![idx];
        if (le?.debitAccountCode) msgs.push(le.debitAccountCode);
        if (le?.creditAccountCode) msgs.push(le.creditAccountCode);
        if (le?.amount) msgs.push(le.amount);
      });
  }
  return msgs;
}

export function shiftJournalEntryLineFieldErrors(
  lines: Record<number, JournalEntryLineFieldErrors> | undefined,
  removedIndex: number,
): Record<number, JournalEntryLineFieldErrors> | undefined {
  if (!lines) return undefined;
  const next: Record<number, JournalEntryLineFieldErrors> = {};
  Object.keys(lines).forEach(k => {
    const idx = Number(k);
    if (idx < removedIndex) next[idx] = lines[idx];
    else if (idx > removedIndex) next[idx - 1] = lines[idx];
  });
  return Object.keys(next).length > 0 ? next : undefined;
}

export function scrollToFirstJournalEntryFieldError(
  fieldErrors: JournalEntryFieldErrors,
  tid: (suffix: string) => string,
  bannerId: string,
): void {
  const scroll = (id: string) => {
    setTimeout(() => {
      document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 120);
  };

  if (fieldErrors.entryDate) {
    scroll(tid('field-entryDate'));
    return;
  }
  if (fieldErrors.processingLevel) {
    scroll(tid('field-processingLevel'));
    return;
  }

  const lineIndices = fieldErrors.lines
    ? Object.keys(fieldErrors.lines).map(Number).sort((a, b) => a - b)
    : [];
  for (const idx of lineIndices) {
    const le = fieldErrors.lines![idx];
    if (le?.debitAccountCode) {
      scroll(tid(`line-${idx + 1}-debit`));
      return;
    }
    if (le?.creditAccountCode) {
      scroll(tid(`line-${idx + 1}-credit`));
      return;
    }
    if (le?.amount) {
      scroll(tid(`line-${idx + 1}-amount`));
      return;
    }
  }
  scroll(bannerId);
}
